mod catalog;
mod components;
mod pages;
mod urls;

use std::{env, sync::Arc};

use axum::{Router, http::header, response::IntoResponse, routing::get};

use crate::catalog::Catalog;

#[cfg(not(target_env = "msvc"))]
#[global_allocator]
static GLOBAL: tikv_jemallocator::Jemalloc = tikv_jemallocator::Jemalloc;

/// The stylesheet generated by the build script.
const TAILWIND_CSS: &str = include_str!(concat!(env!("OUT_DIR"), "/tailwind.css"));

#[tokio::main]
async fn main() {
    let app = Router::new()
        .route("/", get(pages::home))
        .route("/products", get(pages::products))
        .route("/products/{id}", get(pages::product_detail))
        .route("/tailwind.css", get(tailwind_css))
        .with_state(Arc::new(Catalog::load()));

    let port: u16 = match env::var("PORT") {
        Ok(value) => value.parse().expect("PORT must be a valid port number"),
        Err(_) => 3000,
    };
    let listener = tokio::net::TcpListener::bind(("127.0.0.1", port))
        .await
        .unwrap();
    axum::serve(listener, app).await.unwrap();
}

async fn tailwind_css() -> impl IntoResponse {
    ([(header::CONTENT_TYPE, "text/css")], TAILWIND_CSS)
}
